#!/usr/bin/env node

import { HardwareTimingValidator } from './HardwareTimingValidator';
import { chromium, firefox, webkit } from 'playwright';
import * as fs from 'fs/promises';
import * as path from 'path';

interface CLIOptions {
  browsers: string[];
  duration: number;
  output: string;
  headless: boolean;
}

class TimingValidationCLI {
  private validator: HardwareTimingValidator;

  constructor() {
    this.validator = new HardwareTimingValidator();
  }

  async run(options: CLIOptions) {
    console.log('🔬 Psycho-Forge Hardware Timing Validation Suite');
    console.log('================================================\n');

    const results: Record<string, any> = {
      timestamp: new Date().toISOString(),
      options,
      reports: {}
    };

    // Test each browser
    for (const browserName of options.browsers) {
      console.log(`\n📊 Testing ${browserName}...`);

      try {
        const report = await this.testBrowser(browserName, options);
        results.reports[browserName] = report;

        this.printReport(browserName, report);
      } catch (error) {
        console.error(`❌ Failed to test ${browserName}:`, error);
        results.reports[browserName] = { error: String(error) };
      }
    }

    // Generate compatibility matrix
    const allReports = Object.values(results.reports).filter(r => !r.error);
    if (allReports.length > 0) {
      results.compatibilityMatrix = this.validator.generateCompatibilityMatrix(allReports);
    }

    // Save results
    await this.saveResults(results, options.output);

    console.log(`\n✅ Validation complete! Results saved to: ${options.output}`);
  }

  private async testBrowser(browserName: string, options: CLIOptions): Promise<any> {
    const browserTypes = {
      chrome: chromium,
      firefox: firefox,
      safari: webkit
    };

    const browserType = browserTypes[browserName.toLowerCase()];
    if (!browserType) {
      throw new Error(`Unknown browser: ${browserName}`);
    }

    const browser = await browserType.launch({
      headless: options.headless
    });

    try {
      const context = await browser.newContext();
      const page = await context.newPage();

      // Inject validation script
      await page.goto('about:blank');

      // Run validation in browser context
      const report = await page.evaluate(async (duration) => {
        // Create validator class in browser context
        const validator = new (window as any).HardwareTimingValidator();
        return await validator.validate(duration);
      }, options.duration);

      return report;
    } finally {
      await browser.close();
    }
  }

  private printReport(browserName: string, report: any) {
    if (report.error) {
      console.log(`   ❌ Error: ${report.error}`);
      return;
    }

    console.log(`   ✓ FPS: ${report.metrics.fps.toFixed(2)}`);
    console.log(`   ✓ Frame Variance: ${report.metrics.frameVariance.toFixed(2)}ms`);
    console.log(`   ✓ Dropped Frames: ${report.metrics.droppedFrames}`);
    console.log(`   ✓ Refresh Rate: ${report.metrics.refreshRate}Hz`);
    console.log(`   ✓ Timing Precision: ${report.timingPrecision.measured.toFixed(2)}ms (${report.timingPrecision.meetsTarget ? '✅ PASS' : '❌ FAIL'})`);

    if (report.metrics.webGLInfo) {
      console.log(`   ✓ WebGL: ${report.metrics.webGLInfo.version}`);
      console.log(`   ✓ GPU: ${report.metrics.webGLInfo.renderer}`);
    }

    // Print capabilities
    console.log('\n   Capabilities:');
    for (const [key, value] of Object.entries(report.capabilities)) {
      console.log(`     - ${key}: ${value ? '✅' : '❌'}`);
    }

    // Print warnings
    if (report.warnings.length > 0) {
      console.log('\n   ⚠️  Warnings:');
      report.warnings.forEach((warning: string) => {
        console.log(`     - ${warning}`);
      });
    }

    // Print recommendations
    if (report.recommendations.length > 0) {
      console.log('\n   💡 Recommendations:');
      report.recommendations.forEach((rec: string) => {
        console.log(`     - ${rec}`);
      });
    }
  }

  private async saveResults(results: any, outputPath: string) {
    const dir = path.dirname(outputPath);
    await fs.mkdir(dir, { recursive: true });

    await fs.writeFile(
      outputPath,
      JSON.stringify(results, null, 2),
      'utf-8'
    );

    // Also generate a markdown report
    const mdPath = outputPath.replace('.json', '.md');
    await this.generateMarkdownReport(results, mdPath);
  }

  private async generateMarkdownReport(results: any, outputPath: string) {
    let md = '# Psycho-Forge Hardware Timing Validation Report\n\n';
    md += `Generated: ${results.timestamp}\n\n`;

    md += '## Test Configuration\n\n';
    md += `- Duration: ${results.options.duration}ms\n`;
    md += `- Browsers: ${results.options.browsers.join(', ')}\n`;
    md += `- Mode: ${results.options.headless ? 'Headless' : 'Headed'}\n\n`;

    md += '## Browser Results\n\n';

    for (const [browser, report] of Object.entries(results.reports)) {
      md += `### ${browser}\n\n`;

      if ((report as any).error) {
        md += `**Error**: ${(report as any).error}\n\n`;
        continue;
      }

      const r = report as any;

      md += '#### Performance Metrics\n\n';
      md += '| Metric | Value | Status |\n';
      md += '|--------|-------|--------|\n';
      md += `| FPS | ${r.metrics.fps.toFixed(2)} | ${r.metrics.fps >= 55 ? '✅' : '⚠️'} |\n`;
      md += `| Frame Variance | ${r.metrics.frameVariance.toFixed(2)}ms | ${r.metrics.frameVariance <= 5 ? '✅' : '⚠️'} |\n`;
      md += `| Dropped Frames | ${r.metrics.droppedFrames} | ${r.metrics.droppedFrames === 0 ? '✅' : '⚠️'} |\n`;
      md += `| Timing Precision | ${r.timingPrecision.measured.toFixed(2)}ms | ${r.timingPrecision.meetsTarget ? '✅' : '❌'} |\n`;
      md += `| Refresh Rate | ${r.metrics.refreshRate}Hz | - |\n\n`;

      md += '#### Capabilities\n\n';
      md += '| Feature | Supported |\n';
      md += '|---------|----------|\n';
      for (const [key, value] of Object.entries(r.capabilities)) {
        md += `| ${key} | ${value ? '✅' : '❌'} |\n`;
      }
      md += '\n';

      if (r.metrics.webGLInfo) {
        md += '#### Graphics Information\n\n';
        md += `- **Version**: ${r.metrics.webGLInfo.version}\n`;
        md += `- **Vendor**: ${r.metrics.webGLInfo.vendor}\n`;
        md += `- **Renderer**: ${r.metrics.webGLInfo.renderer}\n\n`;
      }

      if (r.warnings.length > 0) {
        md += '#### ⚠️ Warnings\n\n';
        r.warnings.forEach((warning: string) => {
          md += `- ${warning}\n`;
        });
        md += '\n';
      }

      if (r.recommendations.length > 0) {
        md += '#### 💡 Recommendations\n\n';
        r.recommendations.forEach((rec: string) => {
          md += `- ${rec}\n`;
        });
        md += '\n';
      }
    }

    if (results.compatibilityMatrix) {
      md += '## Compatibility Summary\n\n';

      const matrix = results.compatibilityMatrix;

      md += '### Browser Distribution\n\n';
      for (const [browser, count] of Object.entries(matrix.browsers)) {
        md += `- ${browser}: ${count}\n`;
      }
      md += '\n';

      md += '### Platform Distribution\n\n';
      for (const [platform, count] of Object.entries(matrix.platforms)) {
        md += `- ${platform}: ${count}\n`;
      }
      md += '\n';

      md += '### Feature Support\n\n';
      md += '| Feature | Support Rate |\n';
      md += '|---------|-------------|\n';
      for (const [feature, stats] of Object.entries(matrix.capabilities)) {
        const s = stats as any;
        const percentage = (s.supported / s.total * 100).toFixed(0);
        md += `| ${feature} | ${percentage}% (${s.supported}/${s.total}) |\n`;
      }
    }

    await fs.writeFile(outputPath, md, 'utf-8');
  }
}

