  const args = process.argv.slice(2);

  const options: CLIOptions = {
    browsers: ['chrome', 'firefox', 'safari'],
    duration: 5000,
    output: './validation-report.json',
    headless: false
  };

  // Parse command line arguments
  for (let i = 0; i < args.length; i++) {
    switch (args[i]) {
      case '--browsers':
        options.browsers = args[++i].split(',');
        break;
      case '--duration':
        options.duration = parseInt(args[++i]);
        break;
      case '--output':
        options.output = args[++i];
        break;
      case '--headless':
        options.headless = true;
        break;
      case '--help':
        console.log(`
Psycho-Forge Hardware Timing Validation CLI

Usage: npx timing-validate [options]

Options:
  --browsers <list>   Comma-separated list of browsers (default: chrome,firefox,safari)
  --duration <ms>     Test duration in milliseconds (default: 5000)
  --output <path>     Output file path (default: ./validation-report.json)
  --headless          Run browsers in headless mode
  --help              Show this help message

Example:
  npx timing-validate --browsers chrome,firefox --duration 10000 --output ./reports/timing.json
        `);
        process.exit(0);
    }
  }

  const cli = new TimingValidationCLI();
  cli.run(options).catch(error => {
    console.error('Fatal error:', error);
    process.exit(1);
  });
}

