import { EventEmitter } from 'events';

export interface PerformanceMetrics {
  timestamp: number;
  fps: number;
  frameTime: number;
  heapUsed: number;
  heapTotal: number;
  droppedFrames: number;
  renderTime: number;
  updateTime: number;
}

export interface PerformanceThresholds {
  minFPS: number;
  maxFrameTime: number;
  maxHeapUsage: number;
  maxDroppedFrames: number;
}

export class PerformanceMonitor extends EventEmitter {
  private metrics: PerformanceMetrics[] = [];
  private frameTimestamps: number[] = [];
  private lastFrameTime = 0;
  private droppedFrames = 0;
  private monitoring = false;
  private animationId?: number;
  private thresholds: PerformanceThresholds;
  private warningsIssued = new Set<string>();

  constructor(thresholds?: Partial<PerformanceThresholds>) {
    super();
    this.thresholds = {
      minFPS: 55,
      maxFrameTime: 20, // 20ms for 50fps minimum
      maxHeapUsage: 500, // 500MB
      maxDroppedFrames: 5,
      ...thresholds
    };
  }

  start() {
    if (this.monitoring) return;

    this.monitoring = true;
    this.metrics = [];
    this.frameTimestamps = [];
    this.droppedFrames = 0;
    this.lastFrameTime = performance.now();
    this.warningsIssued.clear();

    this.monitorFrame();
  }

  stop() {
    this.monitoring = false;
    if (this.animationId) {
      cancelAnimationFrame(this.animationId);
      this.animationId = undefined;
    }
  }

  private monitorFrame() {
    if (!this.monitoring) return;

    const now = performance.now();
    const frameTime = now - this.lastFrameTime;

    // Detect dropped frames
    if (frameTime > 25) { // More than 25ms indicates dropped frame
      this.droppedFrames++;
    }

    this.frameTimestamps.push(now);
    this.lastFrameTime = now;

    // Keep only last 60 frames
    if (this.frameTimestamps.length > 60) {
      this.frameTimestamps.shift();
    }

    // Calculate metrics every 10 frames
    if (this.frameTimestamps.length % 10 === 0) {
      this.calculateMetrics();
    }

    this.animationId = requestAnimationFrame(() => this.monitorFrame());
  }

  private calculateMetrics() {
    const now = performance.now();
    const fps = this.calculateFPS();
    const avgFrameTime = this.calculateAverageFrameTime();
    const heapInfo = this.getHeapInfo();

    const metrics: PerformanceMetrics = {
      timestamp: now,
      fps,
      frameTime: avgFrameTime,
      heapUsed: heapInfo.used,
      heapTotal: heapInfo.total,
      droppedFrames: this.droppedFrames,
      renderTime: 0, // To be set by renderer
      updateTime: 0  // To be set by update loop
    };

    this.metrics.push(metrics);
    this.emit('metrics', metrics);

    // Check thresholds
    this.checkThresholds(metrics);

    // Keep only last 1000 metrics (about 100 seconds at 10Hz)
    if (this.metrics.length > 1000) {
      this.metrics.shift();
    }
  }

  private calculateFPS(): number {
    if (this.frameTimestamps.length < 2) return 0;

    const duration = this.frameTimestamps[this.frameTimestamps.length - 1] - this.frameTimestamps[0];
    return (this.frameTimestamps.length - 1) / (duration / 1000);
  }

  private calculateAverageFrameTime(): number {
    if (this.frameTimestamps.length < 2) return 0;

    let totalTime = 0;
    for (let i = 1; i < this.frameTimestamps.length; i++) {
      totalTime += this.frameTimestamps[i] - this.frameTimestamps[i - 1];
    }

    return totalTime / (this.frameTimestamps.length - 1);
  }

  private getHeapInfo(): { used: number; total: number } {
    if ('memory' in performance && (performance as any).memory) {
      return {
        used: (performance as any).memory.usedJSHeapSize / 1024 / 1024,
        total: (performance as any).memory.totalJSHeapSize / 1024 / 1024
      };
    }
    return { used: 0, total: 0 };
  }

  private checkThresholds(metrics: PerformanceMetrics) {
    // Check FPS
    if (metrics.fps < this.thresholds.minFPS && metrics.fps > 0) {
      this.issueWarning('low-fps', `FPS dropped below threshold: ${metrics.fps.toFixed(1)} < ${this.thresholds.minFPS}`);
    }

    // Check frame time
    if (metrics.frameTime > this.thresholds.maxFrameTime) {
      this.issueWarning('high-frame-time', `Frame time exceeded threshold: ${metrics.frameTime.toFixed(1)}ms > ${this.thresholds.maxFrameTime}ms`);
    }

    // Check heap usage
    if (metrics.heapUsed > this.thresholds.maxHeapUsage) {
      this.issueWarning('high-memory', `Memory usage exceeded threshold: ${metrics.heapUsed.toFixed(0)}MB > ${this.thresholds.maxHeapUsage}MB`);
    }

    // Check dropped frames
    if (this.droppedFrames > this.thresholds.maxDroppedFrames) {
      this.issueWarning('dropped-frames', `Dropped frames exceeded threshold: ${this.droppedFrames} > ${this.thresholds.maxDroppedFrames}`);
    }
  }

  private issueWarning(type: string, message: string) {
    const key = `${type}-${Math.floor(Date.now() / 5000)}`; // Rate limit to once per 5 seconds

    if (!this.warningsIssued.has(key)) {
      this.warningsIssued.add(key);
      this.emit('warning', { type, message, timestamp: Date.now() });
    }
  }

  recordRenderTime(time: number) {
    if (this.metrics.length > 0) {
      this.metrics[this.metrics.length - 1].renderTime = time;
    }
  }

  recordUpdateTime(time: number) {
    if (this.metrics.length > 0) {
      this.metrics[this.metrics.length - 1].updateTime = time;
    }
  }

  getMetrics(): PerformanceMetrics[] {
    return [...this.metrics];
  }

  getLatestMetrics(): PerformanceMetrics | undefined {
    return this.metrics[this.metrics.length - 1];
  }

  getAverageMetrics(windowSize = 60): Partial<PerformanceMetrics> {
    const recentMetrics = this.metrics.slice(-windowSize);
    if (recentMetrics.length === 0) return {};

    const avg = {
      fps: 0,
      frameTime: 0,
      heapUsed: 0,
      renderTime: 0,
      updateTime: 0
    };

    recentMetrics.forEach(m => {
      avg.fps += m.fps;
      avg.frameTime += m.frameTime;
      avg.heapUsed += m.heapUsed;
      avg.renderTime += m.renderTime;
      avg.updateTime += m.updateTime;
    });

    const count = recentMetrics.length;
    return {
      fps: avg.fps / count,
      frameTime: avg.frameTime / count,
      heapUsed: avg.heapUsed / count,
      renderTime: avg.renderTime / count,
      updateTime: avg.updateTime / count
    };
  }

  reset() {
    this.metrics = [];
    this.frameTimestamps = [];
    this.droppedFrames = 0;
    this.warningsIssued.clear();
  }

  exportMetrics(): string {
    return JSON.stringify({
      metrics: this.metrics,
      summary: {
        duration: this.metrics.length > 0 ? 
          this.metrics[this.metrics.length - 1].timestamp - this.metrics[0].timestamp : 0,
        averages: this.getAverageMetrics(this.metrics.length),
        totalDroppedFrames: this.droppedFrames,
        warningsIssued: Array.from(this.warningsIssued)
      }
    }, null, 2);
  }

  createPerformanceReport(): string {
    const avg = this.getAverageMetrics(this.metrics.length);
    const duration = this.metrics.length > 0 ? 
      (this.metrics[this.metrics.length - 1].timestamp - this.metrics[0].timestamp) / 1000 : 0;

    let report = '# Performance Report\n\n';
    report += `Duration: ${duration.toFixed(1)}s\n\n`;

    report += '## Average Metrics\n\n';
    report += `- FPS: ${avg.fps?.toFixed(1)}\n`;
    report += `- Frame Time: ${avg.frameTime?.toFixed(1)}ms\n`;
    report += `- Memory Usage: ${avg.heapUsed?.toFixed(0)}MB\n`;
    report += `- Render Time: ${avg.renderTime?.toFixed(1)}ms\n`;
    report += `- Update Time: ${avg.updateTime?.toFixed(1)}ms\n\n`;

    report += '## Performance Issues\n\n';
    report += `- Total Dropped Frames: ${this.droppedFrames}\n`;
    report += `- Warnings Issued: ${this.warningsIssued.size}\n\n`;

    if (this.metrics.length > 0) {
      report += '## Performance Over Time\n\n';

      // Find min/max values
      const minFPS = Math.min(...this.metrics.map(m => m.fps));
      const maxFPS = Math.max(...this.metrics.map(m => m.fps));
      const maxMemory = Math.max(...this.metrics.map(m => m.heapUsed));

      report += `- FPS Range: ${minFPS.toFixed(1)} - ${maxFPS.toFixed(1)}\n`;
      report += `- Peak Memory: ${maxMemory.toFixed(0)}MB\n`;
    }

    return report;
  }
}

// Performance monitoring decorator for methods
export function measurePerformance(target: any, propertyKey: string, descriptor: PropertyDescriptor) {
  const originalMethod = descriptor.value;

  descriptor.value = async function(...args: any[]) {
    const start = performance.now();

    try {
      const result = await originalMethod.apply(this, args);
      const duration = performance.now() - start;

      // Emit performance event if available
      if (this.performanceMonitor && typeof this.performanceMonitor.emit === 'function') {
        this.performanceMonitor.emit('method-performance', {
          method: propertyKey,
          duration,
          timestamp: Date.now()
        });
      }

      return result;
    } catch (error) {
      const duration = performance.now() - start;

      if (this.performanceMonitor && typeof this.performanceMonitor.emit === 'function') {
        this.performanceMonitor.emit('method-error', {
          method: propertyKey,
          duration,
          error: String(error),
          timestamp: Date.now()
        });
      }

      throw error;
    }
  };

  return descriptor;
}

