import { describe, it, expect, beforeEach, afterEach, vi } from 'vitest';
import { HardwareTimingValidator } from '../HardwareTimingValidator';

// Mock DOM APIs
const mockCanvas = {
  width: 800,
  height: 600,
  getContext: vi.fn(),
  parentNode: {
    removeChild: vi.fn()
  }
};

const mockWebGLContext = {
  getParameter: vi.fn(),
  getSupportedExtensions: vi.fn(() => ['EXT_texture_filter_anisotropic']),
  getExtension: vi.fn()
};

// Mock performance API
const mockPerformance = {
  now: vi.fn(),
  memory: {
    usedJSHeapSize: 100 * 1024 * 1024 // 100MB
  }
};

describe('HardwareTimingValidator', () => {
  let validator: HardwareTimingValidator;
  let frameCallbacks: ((timestamp: number) => void)[] = [];
  let animationFrameId = 0;

  beforeEach(() => {
    // Setup DOM mocks
    global.document = {
      createElement: vi.fn(() => mockCanvas),
      body: {
        appendChild: vi.fn()
      }
    } as any;

    // Setup canvas context mocks
    mockCanvas.getContext.mockImplementation((type: string) => {
      if (type === 'webgl2' || type === 'webgl' || type === 'experimental-webgl') {
        return mockWebGLContext;
      }
      return null;
    });

    // Setup WebGL mocks
    mockWebGLContext.getParameter.mockImplementation((param: number) => {
      switch (param) {
        case 7937: // VERSION
          return 'WebGL 2.0';
        default:
          return 'Mock Value';
      }
    });

    // Setup performance mocks
    (global as any).performance = mockPerformance;
    let currentTime = 0;
    mockPerformance.now.mockImplementation(() => {
      currentTime += 16.67; // Simulate 60fps
      return currentTime;
    });

    // Setup requestAnimationFrame mock
    frameCallbacks = [];
    (global as any).requestAnimationFrame = vi.fn((callback: (timestamp: number) => void) => {
      frameCallbacks.push(callback);
      return ++animationFrameId;
    });

    (global as any).cancelAnimationFrame = vi.fn();

    // Setup navigator mocks
    (global as any).navigator = {
      userAgent: 'Mozilla/5.0 (Macintosh; Intel Mac OS X 10_15_7) Chrome/120.0.0.0',
      platform: 'MacIntel',
      hardwareConcurrency: 8
    };

    // Setup screen mocks
    (global as any).window = {
      screen: {
        width: 1920,
        height: 1080,
        colorDepth: 24
      }
    };

    // Setup HTMLVideoElement mock
    (global as any).HTMLVideoElement = {
      prototype: {
        requestVideoFrameCallback: true
      }
    };

    // Setup AudioContext mock
    (global as any).AudioContext = class MockAudioContext {};

    validator = new HardwareTimingValidator();
  });

  afterEach(() => {
    vi.clearAllMocks();
  });

  it('should detect browser capabilities correctly', async () => {
    // Start validation
    const validationPromise = validator.validate(100);

    // Simulate frames
    for (let i = 0; i < 10; i++) {
      const timestamp = i * 16.67;
      frameCallbacks.forEach(cb => cb(timestamp));
    }

    const report = await validationPromise;

    expect(report.capabilities).toEqual({
      webGL2: true,
      webGL1: true,
      requestVideoFrameCallback: true,
      highResolutionTime: true,
      webAudioAPI: true
    });
  });

  it('should calculate FPS correctly', async () => {
    const validationPromise = validator.validate(1000);

    // Simulate 60fps for 1 second
    for (let i = 0; i < 60; i++) {
      const timestamp = i * 16.67;
      frameCallbacks.forEach(cb => cb(timestamp));
    }

    const report = await validationPromise;

    expect(report.metrics.fps).toBeCloseTo(60, 1);
  });

  it('should detect dropped frames', async () => {
    const validationPromise = validator.validate(500);

    // Simulate frames with drops
    const timestamps = [0, 16.67, 33.34, 66.68, 83.35]; // Skip one frame
    timestamps.forEach(timestamp => {
      frameCallbacks.forEach(cb => cb(timestamp));
    });

    const report = await validationPromise;

    expect(report.metrics.droppedFrames).toBeGreaterThan(0);
  });

  it('should measure timing precision', async () => {
    // Mock high-precision timing
    let time = 0;
    mockPerformance.now.mockImplementation(() => {
      time += 0.1; // 0.1ms precision
      return time;
    });

    const validationPromise = validator.validate(100);

    // Simulate a few frames
    for (let i = 0; i < 5; i++) {
      frameCallbacks.forEach(cb => cb(i * 16.67));
    }

    const report = await validationPromise;

    expect(report.timingPrecision.measured).toBeLessThanOrEqual(2);
    expect(report.timingPrecision.meetsTarget).toBe(true);
  });

  it('should generate recommendations for poor performance', async () => {
    const validationPromise = validator.validate(500);

    // Simulate poor performance (30fps)
    for (let i = 0; i < 15; i++) {
      const timestamp = i * 33.34; // 30fps
      frameCallbacks.forEach(cb => cb(timestamp));
    }

    const report = await validationPromise;

    expect(report.recommendations).toContain(
      'Frame rate below 60fps. Check system performance and close unnecessary applications.'
    );
  });

  it('should detect WebGL information', async () => {
    const mockDebugInfo = {
      UNMASKED_VENDOR_WEBGL: 37445,
      UNMASKED_RENDERER_WEBGL: 37446
    };

    mockWebGLContext.getExtension.mockImplementation((ext: string) => {
      if (ext === 'WEBGL_debug_renderer_info') {
        return mockDebugInfo;
      }
      return null;
    });

    mockWebGLContext.getParameter.mockImplementation((param: number) => {
      switch (param) {
        case 7937: // VERSION
          return 'WebGL 2.0';
        case 37445: // VENDOR
          return 'Apple Inc.';
        case 37446: // RENDERER
          return 'Apple M1 GPU';
        default:
          return 'Mock Value';
      }
    });

    const validationPromise = validator.validate(100);

    // Run a few frames
    for (let i = 0; i < 5; i++) {
      frameCallbacks.forEach(cb => cb(i * 16.67));
    }

    const report = await validationPromise;

    expect(report.metrics.webGLInfo).toEqual({
      version: 'WebGL 2.0',
      vendor: 'Apple Inc.',
      renderer: 'Apple M1 GPU',
      extensions: ['EXT_texture_filter_anisotropic']
    });
  });

  it('should export report as JSON', async () => {
    const validationPromise = validator.validate(100);

    // Run a few frames
    for (let i = 0; i < 5; i++) {
      frameCallbacks.forEach(cb => cb(i * 16.67));
    }

    const report = await validationPromise;
    const exported = await validator.exportReport(report);
    const parsed = JSON.parse(exported);

    expect(parsed).toHaveProperty('timestamp');
    expect(parsed).toHaveProperty('metrics');
    expect(parsed).toHaveProperty('capabilities');
    expect(parsed).toHaveProperty('exportedAt');
    expect(parsed.version).toBe('1.0.0');
  });

  it('should generate compatibility matrix from multiple reports', async () => {
    const reports = [
      {
        timestamp: Date.now(),
        duration: 1000,
        metrics: {
          fps: 60,
          frameVariance: 2,
          droppedFrames: 0,
          heapUsage: 100,
          refreshRate: 60,
          browserInfo: {
            userAgent: 'Chrome/120.0.0.0',
            platform: 'MacIntel',
            hardwareConcurrency: 8
          },
          displayInfo: {
            width: 1920,
            height: 1080,
            colorDepth: 24,
            refreshRate: 60
          }
        },
        capabilities: {
          webGL2: true,
          webGL1: true,
          requestVideoFrameCallback: true,
          highResolutionTime: true,
          webAudioAPI: true
        },
        timingPrecision: {
          measured: 0.1,
          target: 2,
          meetsTarget: true
        },
        recommendations: [],
        warnings: []
      },
      {
        timestamp: Date.now(),
        duration: 1000,
        metrics: {
          fps: 144,
          frameVariance: 1,
          droppedFrames: 0,
          heapUsage: 150,
          refreshRate: 144,
          browserInfo: {
            userAgent: 'Firefox/120.0',
            platform: 'Win32',
            hardwareConcurrency: 16
          },
          displayInfo: {
            width: 2560,
            height: 1440,
            colorDepth: 32,
            refreshRate: 144
          }
        },
        capabilities: {
          webGL2: true,
          webGL1: true,
          requestVideoFrameCallback: false,
          highResolutionTime: true,
          webAudioAPI: true
        },
        timingPrecision: {
          measured: 0.05,
          target: 2,
          meetsTarget: true
        },
        recommendations: [],
        warnings: []
      }
    ];

    const matrix = validator.generateCompatibilityMatrix(reports);

    expect(matrix.browsers).toEqual({
      Chrome: 1,
      Firefox: 1
    });

    expect(matrix.platforms).toEqual({
      MacIntel: 1,
      Win32: 1
    });

    expect(matrix.refreshRates).toEqual({
      60: 1,
      144: 1
    });

    expect(matrix.capabilities.webGL2).toEqual({
      supported: 2,
      total: 2
    });

    expect(matrix.capabilities.requestVideoFrameCallback).toEqual({
      supported: 1,
      total: 2
    });
  });

  it('should clean up resources after validation', async () => {
    const validationPromise = validator.validate(100);

    // Run a few frames
    for (let i = 0; i < 5; i++) {
      frameCallbacks.forEach(cb => cb(i * 16.67));
    }

    await validationPromise;

    expect(mockCanvas.parentNode.removeChild).toHaveBeenCalledWith(mockCanvas);
    expect(global.cancelAnimationFrame).toHaveBeenCalled();
  });

  it('should handle missing performance.memory gracefully', async () => {
    // Remove memory property
    delete (mockPerformance as any).memory;

    const validationPromise = validator.validate(100);

    // Run a few frames
    for (let i = 0; i < 5; i++) {
      frameCallbacks.forEach(cb => cb(i * 16.67));
    }

    const report = await validationPromise;

    expect(report.metrics.heapUsage).toBe(0);
  });

  it('should generate warnings for poor hardware', async () => {
    // Mock poor hardware
    (global as any).navigator.hardwareConcurrency = 2;

    const validationPromise = validator.validate(100);

    // Run a few frames
    for (let i = 0; i < 5; i++) {
      frameCallbacks.forEach(cb => cb(i * 16.67));
    }

    const report = await validationPromise;

    expect(report.warnings).toContain(
      'Low CPU core count detected. Complex experiments may experience performance issues.'
    );
  });
});

